// Mengemas Insight - Versi Perbaikan untuk Arfan Khoeri
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { message: '❌ Tidak ada data untuk dianalisis' } }];
}

// 1. Kelompokkan data berdasarkan Jam Posting (karena di Sheet ada banyak data per jam)
const groups = {};

items.forEach(item => {
  const data = item.json;
  const jam = data['Jam Posting'];

  if (!groups[jam]) {
    groups[jam] = {
      jam: jam,
      likes: 0,
      comments: 0,
      shares: 0,
      platform: data['Platform'] || 'Instagram',
      count: 0
    };
  }

  // Mengambil angka dari Sheets (memastikan bukan teks kosong)
  groups[jam].likes += parseFloat(data['Likes'] || 0);
  groups[jam].comments += parseFloat(data['Comments'] || 0);
  groups[jam].shares += parseFloat(data['Shares'] || 0);
  groups[jam].count += 1;
});

// 2. Hitung Rata-rata & Engagement Score (Rumus Bobot NF: L + C*2 + S*3)
const results = Object.values(groups).map(g => {
  const avgLikes = g.likes / g.count;
  const avgComments = g.comments / g.count;
  const avgShares = g.shares / g.count;
  const score = avgLikes + (avgComments * 2) + (avgShares * 3);

  return {
    jam: g.jam,
    score: score.toFixed(0),
    avgLikes: avgLikes.toFixed(0),
    avgComments: avgComments.toFixed(0),
    avgShares: avgShares.toFixed(0),
    platform: g.platform,
    totalPost: g.count
  };
});

// 3. Urutkan berdasarkan Skor Tertinggi (Ranking)
results.sort((a, b) => b.score - a.score);

// 4. Format Pesan Telegram (Copy-paste style NF Academy)
let message = '📊 *HASIL ANALISIS WAKTU POSTING TERBAIK*\n';
message += '━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
message += '🏆 *TOP 5 JAM TERBAIK*:\n\n';

results.slice(0, 5).forEach((item, index) => {
  const medal = index === 0 ? '🥇' : (index === 1 ? '🥈' : (index === 2 ? '🥉' : (index + 1) + '.' ));

  message += `${medal} *JAM ${item.jam}:00*\n`;
  message += `📈 Avg Engagement: *${item.score}*\n`;
  message += `❤️ Avg Likes: ${item.avgLikes}\n`;
  message += `💬 Avg Comments: ${item.avgComments}\n`;
  message += `🔄 Avg Shares: ${item.avgShares}\n`;
  message += `📱 Platform: ${item.platform}\n`;
  message += `📊 Total Post: ${item.totalPost} post\n`;
  message += `⭐ SANGAT DIREKOMENDASIKAN\n\n`;
});

message += '🚀 _Gunakan insight ini untuk meningkatkan jangkauan konten Kaffe Tropikal Healing!_';

return [{ json: { message } }];

// 1. Ambil semua data dari input (Google Sheets)
const items = $input.all();

// 2. Looping untuk menghitung engagement di tiap baris
const result = items.map(item => {
  // Ambil data dari kolom (pastikan nama kolom sama persis dengan di Sheets)
  const likes = item.json['Likes'] || 0;
  const comments = item.json['Comments'] || 0;
  const shares = item.json['Shares'] || 0;

  // Rumus engagement bobot NF Academy: likes + (comments * 2) + (shares * 3)
  const engagementScore = likes + (comments * 2) + (shares * 3);

  // Simpan hasil hitungan ke kolom baru bernama 'engagementScore'
  item.json.engagementScore = engagementScore;

  return item;
});

// 3. Urutkan dari skor tertinggi ke terendah (Ranking)
result.sort((a, b) => b.json.engagementScore - a.json.engagementScore);

// 4. Kembalikan data agar bisa lanjut ke node berikutnya
return result;
